#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N,K; scanf("%d %d", &N, &K);
        int *A = (int*)malloc(K*sizeof(int));
        for(int i=0;i<K;i++) scanf("%d", &A[i]);
        int *ans = (int*)malloc(N*sizeof(int));
        int idx=0, prev=0;
        for(int i=0;i<K;i++){
            int a = A[i];
            ans[idx++] = a; // largest first
            for(int x=prev+1; x<a; ++x) ans[idx++] = x;
            prev = a;
        }
        for(int i=0;i<N;i++){
            if(i) printf(" ");
            printf("%d", ans[i]);
        }
        printf("\n");
        free(A); free(ans);
    }
    return 0;
}

