import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder out = new StringBuilder();
        int T = fs.nextInt();
        while (T-- > 0) {
            int N = fs.nextInt();
            int K = fs.nextInt();
            int[] A = new int[K];
            for (int i = 0; i < K; i++) A[i] = fs.nextInt();
            int[] ans = new int[N];
            int idx = 0, prev = 0;
            for (int a : A) {
                ans[idx++] = a; // largest first
                for (int x = prev + 1; x < a; x++) ans[idx++] = x;
                prev = a;
            }
            for (int i = 0; i < N; i++) {
                if (i > 0) out.append(' ');
                out.append(ans[i]);
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
    // Fast scanner for large input
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream stream) { in = new BufferedInputStream(stream); }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

